# Use dynamic symbols to resolve function names for each address
# Extract sorted dynamic symbols with their addresses
aarch64-linux-gnu-nm -D --defined-only /tmp/libmonosgen-2.0.so 2>/dev/null | sort > /tmp/mono_syms.txt

# Function to find nearest symbol for an address
find_symbol() {
  local addr=$1
  # Find the last symbol with address <= our target
  awk -v target="$addr" '{
    if ($1 <= target) { last_addr=$1; last_name=$3 }
  } END {
    if (last_name) {
      offset = strtonum("0x" target) - strtonum("0x" last_addr)
      printf "0x%s -> %s+0x%x\n", target, last_name, offset
    } else {
      printf "0x%s -> <unknown>\n", target
    }
  }' /tmp/mono_syms.txt
}

