# Use Python for proper hex comparison to find nearest symbols
python3 << 'PYEOF'
import subprocess, re

# Get dynamic symbols
result = subprocess.run(
    ['aarch64-linux-gnu-nm', '-D', '--defined-only', '/tmp/libmonosgen-2.0.so'],
    capture_output=True, text=True
)

symbols = []
for line in result.stdout.strip().split('\n'):
    parts = line.split()
    if len(parts) >= 3:
        addr = int(parts[0], 16)
        name = parts[2]
        symbols.append((addr, name))

symbols.sort(key=lambda x: x[0])

def find_symbol(pc):
    best = None
    for addr, name in symbols:
        if addr <= pc:
            best = (addr, name)
        else:
            break
    if best:
        offset = pc - best[0]
        return f"{best[1]}+0x{offset:x}"
    return "<unknown>"

addresses = {
    "Thread 7020 (main - crash thread)": [
        (0x222098, "#01"),
        (0x2241ac, "#02"),
        (0x1abc80, "#03"),
        (0x16de04, "#04"),
    ],
    "Thread 7046 (SGen worker)": [
        (0x2f4b20, "#02"),
        (0x2f4c84, "#03"),
    ],
    "Thread 7048 (Finalizer)": [
        (0x2c1a40, "#02"),
    ],
}

for thread, pcs in addresses.items():
    print(f"=== {thread} ===")
    for pc, frame_num in pcs:
        sym = find_symbol(pc)
        print(f"  {frame_num} pc 0x{pc:016x}  libmonosgen-2.0.so  ({sym})")
    print()
PYEOF

